import PitMap, {Cell, LabelMode} from '@ftcscoring/pit-map';

declare global {
    interface Window {
        pitMapData: Cell[],
        displayTeamNumbers?: Record<number, string>,
        mapConfig: { numbers: boolean, addresses: boolean },
        mapBb: { x: number, y: number, h: number, w: number },
        chosenTeam?: number,
        pitMap: PitMap
    }
}

function setZoom(pitMap : PitMap, newZoom : number) {
    pitMap.setZoom(newZoom);
}

document.addEventListener("DOMContentLoaded", function () {
    window.pitMap = new PitMap({
        id: "pitMap",
        minView: true
    });
    const pitMap = window.pitMap;

    // calculate if need to zoom out for initial fit
    const wrapper = document.getElementById('pitMapWrapper')!;
    let newZoom = 1;
    while(wrapper.clientWidth < (window.mapBb.w * PitMap.BASE_CELL_SIZE * newZoom) && newZoom > .25) {
        newZoom -= .1;
    }
    newZoom = Math.max(.25, newZoom);
    setZoom(pitMap, newZoom);

    if(window.displayTeamNumbers) {
        pitMap.setDisplayTeamNumbers(window.displayTeamNumbers);
    }
    pitMap.setData(window.pitMapData);

    if (!window.mapConfig.numbers) {
        pitMap.setPitLabelMode(window.mapConfig.addresses ? LabelMode.ADDRESS : LabelMode.TEAM);
    }

    if(window.chosenTeam) {
        const team = pitMap.findTeam(window.chosenTeam.toString())
        if(team) {
            pitMap.setHighlighted(team)
        }
    }

    wrapper.dispatchEvent(new CustomEvent("pitMapViewerLoaded", {bubbles: true, cancelable: true}));
});

let zoomBeforePrint: number | null = null;

window.addEventListener("beforeprint", (e) => {
    const pitMap = window.pitMap;
    zoomBeforePrint = pitMap.zoom;
    let newZoom = 2;
    while(1000 < (window.mapBb.w * PitMap.BASE_CELL_SIZE * newZoom) && newZoom > .25) {
        newZoom -= .1;
    }
    newZoom = Math.max(.25, newZoom);
    setZoom(pitMap, newZoom);
    pitMap.prepareForPrint();
})

window.addEventListener("afterprint", () => {
    const pitMap = window.pitMap;
    if(zoomBeforePrint) {
        setZoom(pitMap, zoomBeforePrint);
        zoomBeforePrint = null;
    }
    pitMap.donePrinting();
})
